static void e100_enable_irq(struct nic *nic)  
{ //声明保存中断状态的变量 unsigned long flags; //使用自旋锁保护中断操作，防止多个处理器同时访问 spin_lock_irqsave(&nic->cmd_lock, flags); //使用iowrite8函数将中断屏蔽位设置为irq_mask_none  
